diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..e34b4b68292a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4862,6 +4862,97 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
       return new ICmpInst(NewPred, Op0, Zero);
     }
   }
+  // Fold icmp pred (X / C), X and (X >> C) cmp X
+  {
+    auto FoldDivShrDividend = [&](BinaryOperator *BOp, Value *Dividend,
+                                  bool IsSwapped) -> Instruction * {
+      const APInt *C;
+      Value *X;
+      if (!match(BOp->getOperand(1), m_APInt(C)))
+        return nullptr;
+      X = BOp->getOperand(0);
+      if (X != Dividend)
+        return nullptr;
+      // Determine operation type
+      bool IsSDiv = BOp->getOpcode() == Instruction::SDiv;
+      bool IsUDiv = BOp->getOpcode() == Instruction::UDiv;
+      bool IsAShr = BOp->getOpcode() == Instruction::AShr;
+      bool IsLShr = BOp->getOpcode() == Instruction::LShr;
+      // Only handle division and shift right.
+      if (!IsSDiv && !IsUDiv && !IsAShr && !IsLShr)
+        return nullptr;
+      // For division, divisor must not be 0, 1, -1 (division by 0 is poison, 1 identity, -1 may overflow)
+      // For shift, shift amount must not be 0, and must be less than bitwidth.
+      if (IsSDiv || IsUDiv) {
+        if (C->isZero() || C->abs().ule(1))
+          return nullptr;
+      } else {
+        // Shift amount must be non-zero and less than bitwidth.
+        unsigned BitWidth = C->getBitWidth();
+        if (C->uge(BitWidth) || C->isZero())
+          return nullptr;
+      }
+      bool OpIsSigned = IsSDiv || IsAShr;
+      // Disallow mixed signedness unless equality.
+      bool CmpIsSigned = ICmpInst::isSigned(Pred);
+      if (!I.isEquality() && OpIsSigned != CmpIsSigned)
+        return nullptr;
+      // Map predicate
+      ICmpInst::Predicate NewPred = Pred;
+      if (IsSwapped)
+        NewPred = ICmpInst::getSwappedPredicate(NewPred);
+      bool PredIsSigned = ICmpInst::isSigned(NewPred);
+      // Determine relationship: (X op C) PRED X
+      // If |C| > 1 for division, or C > 0 for shift:
+      // (X op C) <  X  <=> X > 0
+      // (X op C) <= X  <=> X >= 0
+      // (X op C) >  X  <=> X < 0
+      // (X op C) >= X  <=> X <= 0
+      // Equality: (X op C) == X <=> X == 0
+      // Inequality: (X op C) != X <=> X != 0
+      // Works for both signed and unsigned division, and for negative divisor.
+      switch (NewPred) {
+      case ICmpInst::ICMP_SLT:
+      case ICmpInst::ICMP_ULT:
+        return new ICmpInst(PredIsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT,
+                            X, ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SLE:
+      case ICmpInst::ICMP_ULE:
+        return new ICmpInst(PredIsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE,
+                            X, ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SGT:
+      case ICmpInst::ICMP_UGT:
+        return new ICmpInst(PredIsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT,
+                            X, ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_SGE:
+      case ICmpInst::ICMP_UGE:
+        return new ICmpInst(PredIsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE,
+                            X, ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ,
+                            X, ConstantInt::get(X->getType(), 0));
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE,
+                            X, ConstantInt::get(X->getType(), 0));
+      default:
+        return nullptr;
+      }
+    };
+    if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
+                BO0->getOpcode() == Instruction::UDiv ||
+                BO0->getOpcode() == Instruction::AShr ||
+                BO0->getOpcode() == Instruction::LShr)) {
+      if (Instruction *NewI = FoldDivShrDividend(BO0, Op1, /*IsSwapped*/ false))
+        return NewI;
+    }
+    if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+                BO1->getOpcode() == Instruction::UDiv ||
+                BO1->getOpcode() == Instruction::AShr ||
+                BO1->getOpcode() == Instruction::LShr)) {
+      if (Instruction *NewI = FoldDivShrDividend(BO1, Op0, /*IsSwapped*/ true))
+        return NewI;
+    }
+  }

   bool NoOp0WrapProblem = false, NoOp1WrapProblem = false;
   bool Op0HasNUW = false, Op1HasNUW = false;

